update jst_appointment_record
set main_status = #{targetStatus},
    update_by = #{updateBy},
    update_time = #{updateTime}
where appointment_id = #{appointmentId}
  and main_status = #{expectedStatus}
  and del_flag = '0'

mapper.select:
select count(1)
from jst_appointment_record
where contest_id = #{contestId}
  and appointment_date = #{appointmentDate}
  and session_code = #{sessionCode}
  and appointment_type = 'individual'
  and main_status in ('booked', 'partial_writeoff', 'fully_writeoff')
  and del_flag = '0'
